mapper.select:
UPDATE trip.trips
SET
  itinerary_version = itinerary_version + 1,
  updated_at = #{updatedAt}
WHERE id = #{tripId}
  AND status != 'DELETED'
  AND itinerary_version = #{baseVersion}
RETURNING itinerary_version

SELECT count(*)
FROM itinerary.itinerary_items
WHERE trip_id = #{tripId}
  AND itinerary_day_id = #{dayId}
  AND deleted_at IS NULL

mapper.delete:
DELETE FROM itinerary.itinerary_days
WHERE trip_id = #{tripId}
  AND id = #{dayId}
  AND NOT EXISTS (
    SELECT 1
    FROM itinerary.itinerary_items
    WHERE trip_id = #{tripId}
      AND itinerary_day_id = #{dayId}
      AND deleted_at IS NULL
  )

mapper.select:
SELECT EXISTS (
  SELECT 1
  FROM itinerary.itinerary_days
  WHERE trip_id = #{tripId}
    AND id = #{dayId}
)

SELECT count(*)
FROM itinerary.itinerary_days
WHERE trip_id = #{tripId}

SELECT EXISTS (
  SELECT 1
  FROM itinerary.itinerary_items
  WHERE trip_id = #{tripId}
    AND id = #{itemId}
    AND deleted_at IS NULL
)

SELECT id
FROM itinerary.trip_routes
WHERE trip_id = #{tripId}
  AND deleted_at IS NULL
  AND (
    origin_itinerary_item_id = #{itemId}
    OR destination_itinerary_item_id = #{itemId}
  )
ORDER BY created_at ASC, id ASC

SELECT EXISTS (
  SELECT 1
  FROM itinerary.trip_routes
  WHERE trip_id = #{tripId}
    AND id = #{routeId}
    AND deleted_at IS NULL
)

SELECT EXISTS (
  SELECT 1
  FROM itinerary.map_drawings
  WHERE trip_id = #{tripId}
    AND id = #{drawingId}
    AND deleted_at IS NULL
)

mapper.update:
UPDATE itinerary.itinerary_days
SET
  sort_order = #{update.sortOrder},
  updated_at = #{update.updatedAt}
WHERE trip_id = #{update.tripId}
  AND id = #{update.dayId}

UPDATE itinerary.itinerary_items
SET
  itinerary_day_id = #{update.dayId},
  sort_order = #{update.sortOrder},
  updated_by_user_id = #{update.updatedByUserId},
  updated_at = #{update.updatedAt}
WHERE trip_id = #{update.tripId}
  AND id = #{update.itemId}
  AND deleted_at IS NULL

UPDATE itinerary.itinerary_items
SET
  deleted_by_user_id = #{deletedByUserId},
  deleted_at = #{deletedAt},
  updated_by_user_id = #{deletedByUserId},
  updated_at = #{deletedAt}
WHERE trip_id = #{tripId}
  AND id = #{itemId}
  AND deleted_at IS NULL

UPDATE itinerary.trip_routes
SET
  deleted_by_user_id = #{deletedByUserId},
  deleted_at = #{deletedAt},
  updated_by_user_id = #{deletedByUserId},
  updated_at = #{deletedAt}
WHERE trip_id = #{tripId}
  AND id = #{routeId}
  AND deleted_at IS NULL

UPDATE itinerary.map_drawings
SET
  deleted_by_user_id = #{deletedByUserId},
  deleted_at = #{deletedAt},
  updated_by_user_id = #{deletedByUserId},
  updated_at = #{deletedAt}
WHERE trip_id = #{tripId}
  AND id = #{drawingId}
  AND deleted_at IS NULL

mapper.select:
UPDATE itinerary.map_drawings SET geometry = COALESCE(#{update.geometry,jdbcType=VARCHAR}::jsonb, geometry), style = COALESCE(#{update.style,jdbcType=VARCHAR}::jsonb, style), label = COALESCE(#{update.label,jdbcType=VARCHAR}, label), sort_order = COALESCE(#{update.sortOrder,jdbcType=INTEGER}, sort_order), version = version + 1, updated_by_user_id = #{update.updatedByUserId}, updated_at = #{update.updatedAt} WHERE trip_id = #{update.tripId} AND id = #{update.drawingId} AND deleted_at IS NULL
AND version = #{update.expectedVersion}
RETURNING id, itinerary_day_id, drawing_type, geometry_format, geometry::text AS geometry, style::text AS style, label, sort_order, version
